-- Demo tenant branding: logo bytes for GET /api/public/tenants/demo/logo
-- PNG 192px derived from platform-ui/public/assets/demo/logo-demo.png (full file stays in UI assets).
INSERT INTO global.tenant_logo (tenant_id, image_data, mime_type, updated_at)
SELECT id, decode('','base64'), 'image/png', CURRENT_TIMESTAMP
FROM global.tenants WHERE slug = 'demo'
ON CONFLICT (tenant_id) DO UPDATE SET
  image_data = EXCLUDED.image_data,
  mime_type = EXCLUDED.mime_type,
  s3_key = NULL,
  updated_at = EXCLUDED.updated_at;

UPDATE global.tenants SET
  description = '<p>Environnement de démonstration NeoHoods : copropriété fictive pour présenter réservations d''espaces, accès, paiements et notifications. Cadre de vie agréable, espaces communs soignés, chambre d''hôtes, coworking, salle de sport et parkings — données factices.</p>',
  units_count = 4
WHERE slug = 'demo';
